    private func calculateSemitoneDistance() -> Int {
        let noteIndex = Note.allCases.firstIndex(of: note) ?? 0
        let octaveValue = octave.rawValue * 12
        let accidentalValue: Int
        switch accidental {
        case .natural: accidentalValue = 0
        case .sharp: accidentalValue = 1
        case .flat: accidentalValue = -1
        }
        return octaveValue + noteIndex + accidentalValue
    }
